head.script:
//-------------------------------------------------------------------------
// 전역변수
//-------------------------------------------------------------------------
scwin.ed_hlobranCd = "";
scwin.ed_hlobranNm = "";
scwin.ed_odrNo = "";
scwin.ed_searchCheck = "";

scwin.isCall = "";

scwin.vCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.loUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd"); // 회원 점소 데이터
// scwin.loUpperLobranCd = "4AA"; // 회원 점소 데이터
scwin.oldData = "";
scwin.eventCnt = 0;
scwin.sbmCheck = false;
//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {

    ica_wrkDt.setValue(scwin.vCurDate);
    ed_cvsslMgntNo.focus();


    btn_mainSave.setDisabled(true);
    gr_RowLeft.setDisabled(true);
    gr_RowRight.setDisabled(true);

    scwin.f_DivHoldEachWorkPlanList() // 본선 정보 조회

    ed_cvsslMgntNo.focus();

    const codeOptions = [
        { grpCd: "SD060", compID: "acb_impExpClsCd" }, // 셀렉트
        { grpCd: "OP241", compID: "acb_wrkMthdCd" }, // 셀렉트
        { grpCd: "OP117", compID: "acb_shiftClsCd" }, // 셀렉트
        { grpCd: "OP265", compID: "gr_main2:wagePayClsCd", opt:{"range" : "2,1"} }, // 셀렉트
    ];
    $c.data.setCommonCode(codeOptions);	


    acb_wrkMthdCd.setValue("AA");
};




//-------------------------------------------------------------------------
// 본선작업계획 상세 조회 테이블 생성
//-------------------------------------------------------------------------
scwin.f_DivHoldEachWorkPlanList = function() {

// 1.본선기본정보조회
let vsslNm = ""; //선박명
let lineNm = ""; //LINE명
let shpCoNm = ""; //선사명
let portcnt = ""; //수출항차
let repKcg = ""; //수입대표화종
let wrkPlNm = ""; //작업장명
let arrvlportDtm = ""; //입항일시
let deprtportDtm = ""; //출항일시        
let lobranCd =""; //작업점소  
// let lobranCd ="4AA"; //작업점소  


    if (ds_main1.getTotalRow() > 0) {
        vsslNm = ds_main1.getCellData(0, "vsslNm");
        lineNm = ds_main1.getCellData(0, "lineNm");
        shpCoNm = ds_main1.getCellData(0, "shpCoNm");
        portcnt = ds_main1.getCellData(0, "portcnt");
        repKcg = ds_main1.getCellData(0, "repKcg");
        wrkPlNm = ds_main1.getCellData(0, "wrkPlNm");
        arrvlportDtm = $c.gus.cfGetFormatStr(ds_main1.getCellData(0, "arrvlportDtm"), "####/##/## ##:##");
        deprtportDtm = $c.gus.cfGetFormatStr(ds_main1.getCellData(0, "deprtportDtm"), "####/##/## ##:##");
        lobranCd = ds_main1.getCellData(0, "lobranCd");
    }

    ed_vsslNm.setValue(vsslNm);
    ed_lineNm.setValue(lineNm);
    ed_shpCoNm.setValue(shpCoNm);

    if(ds_main1.getTotalRow() == 0) {
        // tr_wrkInfo.setStyle("display", "none");
    } else {

        let impExp = "";
        if (ds_main1.getCellData(0, "impExpClsCd") =="I"){
            impExp = "수입";
        }else{
            impExp = "수출";
        }

        tr_wrkInfo.setStyle("display", "table-row");
        ed_portcnt.setValue(portcnt);
        ed_repKcg.setValue(repKcg);
        ed_impExp.setValue(impExp);
        ed_wrkPlNm.setValue(wrkPlNm);
        ed_arrvlportDtm.setValue(arrvlportDtm);
        ed_deprtportDtm.setValue(deprtportDtm);
    }



    // add by hanchoice - 20061120
	if(lobranCd == "4AA" ) { //인천인  경우     
		btn_openUnionPopUp.setDisabled(false);
	}
	else if(lobranCd == "3AA" ) { //충남당진 인  경우     
		btn_openUnionPopUp.setDisabled(false);
	}
	else{  // 인천이 아닌 경우  
		btn_openUnionPopUp.setDisabled(true);
	}


}


//-------------------------------------------------------------------------
// 대문자 변환
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

//-------------------------------------------------------------------------
// 조회 버튼 클릭 f_Retrieve
//-------------------------------------------------------------------------
scwin.btn_retrieve_onClick = async function (e) {
    // 검색조건 필수 입력 체크
  	if (!await $c.gus.cfValidate([ed_cvsslMgntNo,acb_impExpClsCd,acb_wrkMthdCd])) {	// 본선관리번호, 수출입구분, 작업방법, 작업일자 
  		return;
	}

    if(await ica_wrkDt.getValue() == "") {
        $c.win.alert("작업일자은(는) 필수 입력 항목입니다.");
        return;
    }

	dma_search.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());  // 본선관리번호
	dma_search.set("impExpClsCd", acb_impExpClsCd.getValue());		  // 수출입구분
	dma_search.set("wrkDt", ica_wrkDt.getValue());		              // 작업일자
	dma_search.set("shiftClsCd", acb_shiftClsCd.getValue());		  // SHIFT구분
	dma_search.set("wrkplCd", ds_main1.getCellData(0, "upperWrkPlCd"));  // 작업장 : 선석의 상위 작업장인 부두 로 
	dma_search.set("wrkMthdCd", acb_wrkMthdCd.getValue());		  // 작업방법
	scwin.ed_searchCheck  = "1";

    // 서브미션 수행 순서 때문에 2번 연속으로 조회 
    scwin.search();

    // $c.sbm.execute(sbm_search);

};

//-------------------------------------------------------------------------
// 조회시 ds_main3에서 사용할 일용코드 데이터셋 자체가 후 순위에 오기 때문에 로드가 안되어, 두번 돌림
//-------------------------------------------------------------------------
scwin.search = async function() {

    let e = await $c.sbm.execute(sbm_search2);

    if(e.responseJSON.resultDataSet[0].Msg == "SUCC") { 

        ds_main3.clearFilter();
        let shiftClsCd2 = ds_main2.getCellData(0, "shiftClsCd");
        let lunionOrgCd2 = ds_main2.getCellData(0, "lunionOrgCd");

        let filterOptions = {
            type : "row",
            colIndex : "shiftClsCd",
            key : shiftClsCd2,
            condition : "and"
        }


        let filterOptions2 = {
            type : "row",
            colIndex : "lunionOrgCd",
            key : lunionOrgCd2,
            condition : "and"
        }

        ds_main3.setColumnFilter(filterOptions)
        ds_main3.setColumnFilter(filterOptions2)


        $c.sbm.execute(sbm_search);
    }

}


//-------------------------------------------------------------------------
// 저장 버튼 클릭
//-------------------------------------------------------------------------
scwin.btn_mainSave_onClick = async function (e) {
    // 투입 반원정보 그리드 validate
/*    let validArray = [
        {id:"shiftClsCd", name: "SHIFT", mandatory: true, key:true},
        {id:"lunionOrgCd", name: "반코드", mandatory: true, key:true},
        {id:"chiefNm", name: "반장", mandatory: true, key:true},
        {id:"chiefExceptStaffCnt", name: "반장외인원수", minNumber : 0},
        {id:"wrkStDt", name: "시작일자",  format: "YYYYMMDD"},
        {id:"wrkStHh", name: "시작시간",  format: "HHmm"},
        {id:"wrkEndDt", name: "종료일자",  format: "YYYYMMDD"},
        {id:"wrkEndHh", name: "종료시간",  format: "HHmm"}
    ];

    ret = await $c.gus.cfValidateGrid(gr_main2, null, null, validArray, "투입반원정보");

    if (! ret) {
        return;
    }


    // 일용정보 그리드 validate
    let validArray2 = [
        {id:"scDtlSeqNo", name: "매출입항목코드", mandatory: true, key:true}
    ];

    ret2 = await $c.gus.cfValidateGrid(gr_main3, null, null, validArray2, "일용정보");


    if (! ret2) {
        return;
    }

*/
    if (! await $c.gus.cfValidate(gr_main2, null, true)){
    	return;
    }

    if (! await $c.gus.cfValidate(gr_main3, null, true)){
    	return;
    }


    if(! await $c.win.confirm(MSG_CM_CRM_001)) {
        return;
    }


    for(i=0; i < ds_main2.getTotalRow(); i++){

    	if(ds_main2.getCellData(i, "wagePayClsCd") == "0"){

    	}else{
    	 	if(ds_main2.getCellData(i, "wageAmt") == 0){
				$c.win.alert("추가LumpSum 이나 단독LumpSum 인 경우 금액을 입력하시오.");

		   		ds_main2.setRowPosition(i);
		   		gr_main2.setFocusedCell(i, "wageAmt");
				return;
			} 

			//Hold No 정보 set 
			if((ds_main2.getCellData(i, "holdNo")== undefined ) || (ds_main2.getCellData(i, "holdNo") == "") ){
				$c.win.alert("추가LumpSum 이나 단독LumpSum 인 경우 Hold No 입력하시오."); 
		   		ds_main2.setRowPosition(i);
		   		gr_main2.setFocusedCell(i, "holdNo");
				return;
			}  
    	}
    }

	//중복확인
	for(i=0; i < ds_main2All.getTotalRow(); i++){

		for (j=0; j < ds_main2.getTotalRow(); j++) {

			if(ds_main2.getRowStatus(j) == "C"){

				if (ds_main2All.getCellData(i,"wrkStDt") == ds_main2.getCellData(j,"wrkStDt")        
				 && ds_main2All.getCellData(i,"lunionOrgCd") == ds_main2.getCellData(j,"lunionOrgCd")
				 && ds_main2All.getCellData(i,"shiftClsCd") == ds_main2.getCellData(j,"shiftClsCd")  
				 && i != j) {                                                                     
					$c.win.alert((j+1)+"번째 반원은 중복 데이터이므로 입력하실 수 없습니다.");            
					ds_main2All.setRowPosition(i);                                                       
				 	return;                                                                         
				}    
   			}
		}
	}//I2012008



	//기등록 된 반원이 있다면
	if(scwin.isCall){
		//등록된 행만큼 돌면서
		for (i=0; i < ds_main2.getTotalRow(); i++) {

			//삭제상태가 아니면 
			if(ds_main2.getRowStatus(i) != "D"){

				//삽입상태로 바꾸어라. 왜? 
				ds_main2.modifyRowStatus(i, "C");
			}
		}
	}

    sbm_main.userData1="noError"
    await $c.sbm.execute(sbm_main);


};


//-------------------------------------------------------------------------
// 본선관리번호 조회
//-------------------------------------------------------------------------
scwin.btn_cvsslMgntNo_onClick = async function (e) {

    let url = "/ui/ds/op/wrkrslts/wagewrkrslts/op_307_01_20p.xml";

    let options = {
        id: "taxPop", 
        type: "",
        popupName: "본선관리번호검색팝업",
        width:  1100,                   
        height: 650
    };

    let args = {
        "cvsslMgntNo" : ed_cvsslMgntNo.getValue()
    }



    let rtnList = await $c.win.openPopup(url, options, args);

    if(rtnList != null) {
        ed_cvsslMgntNo.setValue(rtnList[0]);
        acb_impExpClsCd.setValue(rtnList[1]);
        ica_wrkDt.setValue(rtnList[2])
    }

};


//-------------------------------------------------------------------------
// 조회 서브미션 성공시
//-------------------------------------------------------------------------
scwin.sbm_search_submitDone = function (e) {

    scwin.f_DivHoldEachWorkPlanList(); // 본선정보조회 

    scwin.ed_odrNo = ds_main0.getCellData(0, "stvWageOdrNo");

    if(ds_main2.getTotalRow() > 0) {
        scwin.isCall = false;
        btn_mainSave.setDisabled(false);
        gr_main2.setFocusedCell(0, 1);

        gr_RowLeft.setDisabled(false);
        gr_RowRight.setDisabled(false);
        spa_totalRows1.setValue(ds_main2.getTotalRow());        
    } else {
        $c.win.alert(MSG_CM_WRN_002);

        scwin.isCall = true;
        btn_mainSave.setDisabled(true);
    }


    ds_main3.clearFilter();
    let shiftClsCd2 = ds_main2.getCellData(0, "shiftClsCd");
    let lunionOrgCd2 = ds_main2.getCellData(0, "lunionOrgCd");

    let filterOptions = {
        type : "row",
        colIndex : "shiftClsCd",
        key : shiftClsCd2,
        condition : "and"
    }


    let filterOptions2 = {
        type : "row",
        colIndex : "lunionOrgCd",
        key : lunionOrgCd2,
        condition : "and"
    }

    ds_main3.setColumnFilter(filterOptions)
    ds_main3.setColumnFilter(filterOptions2)

    // 일용정보 필터
    // scwin.gr_main2_clickRow(gr_main2.getFocusedRowIndex(), "", "");

};



//-------------------------------------------------------------------------
// 저장 서브미션 성공시
//-------------------------------------------------------------------------
scwin.sbm_main_submitDone = async function (e) {
    try{
        if (await e.responseJSON.resultDataSet[0].Code < 0) {
            await $c.win.alert(e.responseJSON.resultDataSet[1].Msg);

            if(scwin.sbmCheck == true) {
                let url = "/ui/ds/op/wrkrslts/wagewrkrslts/op_307_01_03p.xml";

                let options = {
                    id: "taxPop", 
                    type: "browserPopup",
                    popupName: "본선관리번호검색팝업",
                    width:  1100,                   
                    height: 650
                };


                let args = new Array();
                args[0] = ds_main3.getCellData(gr_main3.getFocusedRowIndex(), "odrNo");
                args[1] = ds_main3.getCellData(ds_main3.getRowPosition(), "lunionOrgCd");
                args[2] = ds_main3.getCellData(ds_main3.getRowPosition(), "wrkDt"); 
                args[4] = ds_main3.getCellData(ds_main3.getRowPosition(), "impExpClsCd");   
                args[5] = ds_main3.getCellData(ds_main3.getRowPosition(), "shiftClsCd");  

                args[7]  = ds_main1.getCellData(0, "wrkPlNm");
                args[8]  = ds_main1.getCellData(0, "cvsslMgntNo");  
                args[12] =0;

                let rtnList = await $c.win.openPopup(url, options, args);
            }

            scwin.sbmCheck = false;

            return; //onFail
        }

        $c.win.alert(MSG_CM_INF_001);
        $c.sbm.execute(sbm_search); // 조회
    } catch (e) {
       console.log("sbm_main_submitdone : " + e);
    }


};


//-------------------------------------------------------------------------
// 오더번호 데이터셋 조회 완료시
