//-------------------------------------------------------------------------
// 투입반원정보 그리드 행추가
//-------------------------------------------------------------------------
scwin.f_ds_main2_AddRow = function() {

    let row = ds_main2.insertRow();

    ds_main2.setCellData(row, "odrNo", ds_main0.getCellData(0, "stvWageOdrNo")) ;  // 오더번호
    ds_main2.setCellData(row, "wrkplcd", ds_main1.getCellData(0, "upperWrkPlCd"));       // 작업장코드
    ds_main2.setCellData(row, "wrkDt", ica_wrkDt.getValue());                          // 작업일자
    ds_main2.setCellData(row, "cvsslMgntNo", ed_cvsslMgntNo.getValue());       // 본선관리번호
    ds_main2.setCellData(row, "impExpClsCd", acb_impExpClsCd.getValue());             // 수입수출구분코드
    ds_main2.setCellData(row, "wrkMthdCd", acb_wrkMthdCd.getValue());               // 작업방법코드
    ds_main2.setCellData(row, "wagePayClsCd", "0");  

    gr_main2.setFocusedCell(row, 1);
    scwin.gr_main2_clickRow(row, "","");

}


//-------------------------------------------------------------------------
// 투입반원정보 그리드 행삭제
//-------------------------------------------------------------------------
scwin.f_ds_main2_DeleteRow = function() {
    let main2Row = gr_main2.getFocusedRowIndex();

    if(main2Row < 0) {
        return;
    } else {
        if(ds_main2.getRowStatus(main2Row) == "C") {
            ds_main2.removeRow(main2Row);
        } else {
            ds_main2.deleteRow(main2Row);
        }

        for(i = 0; i < ds_main3.getRowCount(); i++) {
            ds_main3.deleteRow(i);
        }
    }

    gr_main2.setFocusedCell(main2Row, 0);
}


//-------------------------------------------------------------------------
// 일용정보 그리드 행추가
//-------------------------------------------------------------------------
scwin.f_ds_main3_AddRow = async function() {

	if(ds_main2.getTotalRow() == 0){
		$c.win.alert("투입반원정보 Grid 에 행을 추가하여 주십시오.");
		return;
	}
	if(ds_main2.getModifiedIndex() != 0)
	{
		if(await $c.win.confirm($c.data.getMessage("투입반원정보에 대하여 " + MSG_CM_CRM_015))) {
            scwin.btn_mainSave_onClick();
        } else {
            return ;
        }  
	}

	let row3 = ds_main3.insertRow();	// 행추가	
	let lobranCd = ds_main1.getCellData(0, "lobranCd");
	let row = ds_main2.getRowPosition();
    let main3Row = row3;
	if (row >= 0) {
		ds_main3.setCellData(main3Row, "odrNo", ds_main2.getCellData(row, "odrNo"));
		ds_main3.setCellData(main3Row, "wageRsltsSeq", 0);
		ds_main3.setCellData(main3Row, "lunionOrgCd", ds_main2.getCellData(row, "lunionOrgCd"));
		ds_main3.setCellData(main3Row, "inputWrkStp", ds_main2.getCellData(row, "inputWrkStp"));
		ds_main3.setCellData(main3Row, "stvWrkIndictNo", ds_main2.getCellData(row, "stvWrkIndictNo"));
		ds_main3.setCellData(main3Row, "cvsslMgntNo", ds_main2.getCellData(row, "cvsslMgntNo"));
		ds_main3.setCellData(main3Row, "impExpClsCd", ds_main2.getCellData(row, "impExpClsCd"));
		ds_main3.setCellData(main3Row, "shiftClsCd", ds_main2.getCellData(row, "shiftClsCd"));
		ds_main3.setCellData(main3Row, "wrkplCd", ds_main1.getCellData(0, "upperwrkplCd"));       // 작업장코드
		ds_main3.setCellData(main3Row, "wrkDt", ds_main2.getCellData(row, "wrkDt"));
		ds_main3.setCellData(main3Row, "wageVolUnit", "03");
		ds_main3.setCellData(main3Row, "wageUnitClsCd", "01");
		ds_main3.setCellData(main3Row, "wagePayClsCd", ds_main2.getCellData(row, "wagePayClsCd"));
		ds_main3.setCellData(main3Row, "wageRsltsYn", "0");		
		ds_main3.setCellData(main3Row, "wrkMthdCd", ds_main2.getCellData(row, "wrkMthdCd"));		
		ds_main3.setCellData(main3Row, "holdNo", "0"); 
	}

    gr_main3.setFocusedCell(main3Row, 0);


}

//-------------------------------------------------------------------------
// 일용정보 그리드 셀 편집 후 (일용코드값 때문에 사용)
//-------------------------------------------------------------------------
scwin.gr_main3_AfterEdit = function (rowIndex, columnIndex, value) {

    let colid = gr_main3.getColumnID(columnIndex);

    // getMatchedColumnData 를 사용하면 배열로 return 되기 때문에 값은 1개여서 배열 0번째 데이터로 추출함
    // ds_selpchItemCd 의 Code열 값이 primary가 되지 못하고 Name이랑 둘이 합쳐서 사용해야해서 Code값 넣기 위해 Name도 사용함
    let selpchItemCd = ds_selpchItemCd.getMatchedColumnData("selpchItemNm",ds_main3.getCellData(rowIndex, "selpchItemNm"), "selpchItemCd")[0];
    let scDtlSeqNo = ds_selpchItemCd.getMatchedColumnData("selpchItemNm", ds_main3.getCellData(rowIndex, "selpchItemNm"), "scDtlSeqNo")[0];

 	if(colid == "selpchItemNm"){
		ds_main3.setCellData(rowIndex , "selpchItemCd", selpchItemCd);
		ds_main3.setCellData(rowIndex, "scDtlSeqNo", scDtlSeqNo);
	}


    if(colid == "wageVol" && value == "") {
        ds_main3.setCellData(rowIndex, colid, 0);
    }

    if(colid == "holdNo" && value == "") {
        ds_main3.setCellData(rowIndex, colid, 0);
    }

};

//-------------------------------------------------------------------------
// 일용정보 데이터셋 조회 완료시 데이터셋 필터 걸기
//-------------------------------------------------------------------------
scwin.ds_main3_ondataload = function () {

    let condition = {};
    let shiftClsCd2 = ds_main2.getCellData(0, "shiftClsCd");
    let lunionOrgCd2 = ds_main2.getCellData(0, "lunionOrgCd");


    let filterOptions = {
        type : "row",
        colIndex : "shiftClsCd",
        key : shiftClsCd2,
        condition : "and"
    }

    let filterOptions2 = {
        type : "row",
        colIndex : "lunionOrgCd",
        key : lunionOrgCd2,
        condition : "and"
    }

    ds_main3.setColumnFilter(filterOptions)
    ds_main3.setColumnFilter(filterOptions2)

    gr_main3.setFocusedCell(0, 1);

    spa_totalRows2.setValue(ds_main3.getRowCount());
};

//-------------------------------------------------------------------------
// 필터용
//-------------------------------------------------------------------------
scwin.gr_main2_clickRow = function (rowIndex, columnIndex, columnId) {
    ds_main3.clearFilter();
    let shiftClsCd2 = ds_main2.getCellData(rowIndex, "shiftClsCd");
    let lunionOrgCd2 = ds_main2.getCellData(rowIndex, "lunionOrgCd");
        let wagePayClsCd = ds_main2.getCellData(rowIndex, "wagePayClsCd");

        if(ds_main2.getRowStatus(rowIndex) == "C"){
            gr_main2.setCellReadOnly(rowIndex, "shiftClsCd", false);			
            gr_main2.setCellReadOnly(rowIndex, "lunionOrgCd", false);			
            gr_main2.setCellReadOnly(rowIndex, "chiefNm",true);		
            gr_main2.setCellReadOnly(rowIndex, "inputWrkStp",false);	
            gr_main2.setCellReadOnly(rowIndex, "duseAdptYn", false);		    	    	    	    	    	
        } else {

            gr_main2.setCellReadOnly(rowIndex, "shiftClsCd", true);			
            gr_main2.setCellReadOnly(rowIndex, "lunionOrgCd",true);				
            gr_main2.setCellReadOnly(rowIndex, "chiefNm",true);				
            gr_main2.setCellReadOnly(rowIndex, "inputWrkStp",true);	

        }


        if ( wagePayClsCd == "0" ) {
            gr_main2.setCellReadOnly(rowIndex, "wageAmt", true);
            gr_main2.setCellReadOnly(rowIndex, "holdNo",true);
        }
        else {
            gr_main2.setCellReadOnly(rowIndex, "wageAmt", false);
            gr_main2.setCellReadOnly(rowIndex, "holdNo", false);
        }


    if(ds_main2.getRowStatus(rowIndex) == "C") {
        shiftClsCd2 = null;
        lunionOrgCd2 = null;
    }

    let filterOptions = {
        type : "row",
        colIndex : "shiftClsCd",
        key : shiftClsCd2,
        condition : "and"
    }


    let filterOptions2 = {
        type : "row",
        colIndex : "lunionOrgCd",
        key : lunionOrgCd2,
        condition : "and"
    }

    ds_main3.setColumnFilter(filterOptions)
    ds_main3.setColumnFilter(filterOptions2)

    gr_main3.setFocusedCell(0, 1);
    spa_totalRows2.setValue(ds_main3.getRowCount());


};


