        return;        
    }

    if(await ds_main3.getModifiedIndex().length > 0) {   
        if(!await $c.win.confirm(MSG_CM_CRM_015)) {
        } else {
            return    
        }
    }


    let url = "/ui/ds/op/wrkrslts/wagewrkrslts/op_307_01_03p.xml";

        let options = {
            id: "taxPop", 
            type: "browserPopup",
            popupName: "노조 편성내역 조정팝업",
            width:  580,                   
            height: 750
        };


        let args = new Array();
        args[0] = ds_main3.getCellData(gr_main3.getFocusedRowIndex(), "odrNo");
        args[1] = ds_main3.getCellData(ds_main3.getRowPosition(), "lunionOrgCd");
        args[2] = ds_main3.getCellData(ds_main3.getRowPosition(), "wrkDt"); 
        args[4] = ds_main3.getCellData(ds_main3.getRowPosition(), "impExpClsCd");   
        args[5] = ds_main3.getCellData(ds_main3.getRowPosition(), "shiftClsCd");  

        args[7]  = ds_main1.getCellData(0, "wrkPlNm");
        args[8]  = ds_main1.getCellData(0, "cvsslMgntNo");  
        args[12] =0;

        let rtnList = await $c.win.openPopup(url, options, args);

};



//-------------------------------------------------------------------------
// 그리드 셀 편집 전
//-------------------------------------------------------------------------
scwin.gr_main2_onbeforeedit = function (rowIndex, columnIndex, value) {
    scwin.oldData = value;
};

//-------------------------------------------------------------------------
// 그리드 셀 편집 후 
//-------------------------------------------------------------------------
scwin.gr_main2_afterEdit = function (rowIndex, columnIndex, value) {
    let colid = gr_main2.getColumnID(columnIndex);



    if(colid == "lunionOrgCd") {
        if(scwin.oldData != value && value != "") {
            scwin.f_openCommPopUpGrid(rowIndex,"T",colid, "onafteredit");
        } else if(scwin.oldData != value && value == "") {
            ds_main2.setCellData(rowIndex, "chiefNm", "");
            ds_main2.setCellData(rowIndex, "chiefExceptStaffCnt","");
            ds_main2.setCellData(rowIndex, "lunionOrgCd", "");
            scwin.f_openCommPopUpGrid(rowIndex,"T",colid, "onafteredit");
        } else if(value == "") {
            return;
        }

    } else if(colid == "chiefExceptStaffCnt" && value == "") {
        ds_main2.setCellData(rowIndex, colid, 0);
    } else if(colid == "hatchCoverOpenCnt" && value == "") {
        ds_main2.setCellData(rowIndex, colid, 0);
    } else if(colid == "wageAmt" && value == "") {
        ds_main2.setCellData(rowIndex, colid, 0);
    }

}

