    scwin.f_openCommPopUpGrid(rowIndex,"F",colid, "ontextimageclick");
}

//-------------------------------------------------------------------------
// Popup 처리 : 그리드에서 입력된 코드정보로 품명을 조회
//-------------------------------------------------------------------------
scwin.f_openCommPopUpGrid = function(row, pClose,colid) {
    let evNm = arguments[3] || "";

    if (evNm && $c.win.getEventList(gr_main2, evNm)) {
        scwin.eventCnt++;
    }

    let value = ds_main2.getCellData(row, colid);


    $p.setTimeout(function () {
        scwin.eventCnt = 0;
    }, { delay: 1500 });


  	// 선언부
	var rtnList;  // 공통POP-UP -> 요청화면 
	var pCode = "";
	var pName = "";

    if(colid == "lunionOrgCd") {
        //  부품 코드팝업			
        pCode = ds_main2.getCellData(row, colid);		//  코드
        pName = "";		//  코드
        let wrkPlcd = ds_main2.getCellData(row, "wrkplcd");
        //pCode = "Y";
        var strParam = "";
        strParam = ""+","+wrkPlcd;
        udc_grid_popUp.setSelectId("wageLunionOrgCdLevel3");     

        if (scwin.eventCnt == 1) {

            ds_main2.setCellData(row, colid, "");
            ds_main2.setCellData(row, "chiefNm", "");

            udc_grid_popUp.cfCommonPopUp(
                scwin.udc_grid_popup_callBack	// XML상의 SELECT ID	
                ,pCode					// 화면에서의 ??? Code Element의	Value
                ,pName					// 화면에서의 ??? Name Element의	Value
                ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                ,null					// Title순서	
                ,null					// 보여주는 각 컬럼들의 폭	
                ,null					// 컬럼중에서 숨기는	컬럼 지정	
                ,strParam					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                ,500					// POP-UP뛰을때 원도우의	사용자 정의	폭
                ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                ,null					// 윈도우 위치 Y좌표	
                ,null					// 윈도우 위치 X좌표
                ,null					// 중복체크여부	("F")
                ,"T"					// 전체검색허용여부	("F")
                ,null				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm"
            ); 
        } 
    }
    return false;
}


