    let row = gr_main2.getFocusedRowIndex();

    $c.gus.cfSetGridReturnValue(rtnList, ds_main2, row, "tmpField1", "tmpField2", ["lunionOrgCd","tmpField3","chiefNm","chiefExceptStaffCnt"]);	

}


